-- Seed: products from DWB 2026 catalogs + TENDON (mytendon.com). Idempotent upsert.
on conflict (code) do update set
  name=excluded.name, category=excluded.category, type=excluded.type, description=excluded.description,
  features=excluded.features, specs=excluded.specs, attributes=excluded.attributes, colors=excluded.colors,
  weight=excluded.weight, size_weights=excluded.size_weights, certification=excluded.certification,
  made_in=excluded.made_in, image=excluded.image, status=excluded.status, rating=excluded.rating,
  source=excluded.source, available=excluded.available, sort=excluded.sort, updated_at=now();
