insert into public.products (code,name,category,type,description,features,specs,attributes,colors,weight,size_weights,certification,made_in,image,status,rating,source,available,sort) values
('71762', 'Bud', 'Belay Devices', 'ST', 'The EDELRID classic in a new design. No further explanation required. For universal usage such as abseiling and belaying.', '["Suitable for single ropes from 7.8–12.0 mm"]'::jsonb, '[{"label": "Certification", "value": "EN 15151-2"}, {"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "76 mm"}, {"label": "Length", "value": "130 mm"}, {"label": "Approved rope diameter", "value": "7.8–12 mm"}, {"label": "Weight", "value": "110 g"}]'::jsonb, '["Manual"]'::jsonb, '["royal 360", "slate 663"]'::jsonb, '110 g', '[]'::jsonb, 'EN 15151-2', null, '/images/products/71762.webp', 'BELAY', 'EN 15151-2', '', true, 0),
('73742', 'Giga Jul', 'Belay Devices', 'ST', 'The most versatile ever belay device. The GIGA JUL is a standard and assisted braking tuber in one. The assisted braking function which supports the braking force can be activated or disabled by an intelligent mechanism. For situation-dependent belaying and abseiling, especially in alpine terrain.', '["Small eyelet for releasing unit with a carabiner when bringing up your partner", "Suitable for 7.1–10.0 mm ropes", "Intelligent hybrid design: body made of ultra-light aluminum, areas susceptible to abrasion made of robust stainless steel", "Guide mode: simple and rapid abseiling and bringing up seconds plus comfortable belaying from a belay station as a doubled rope", "Assisted braking guide mode: brake boost for catching falls in leader mode", "Rope can be paid out faster in assisted braking guide mode by holding the device in the ''open'' position with the thumb"]'::jsonb, '[{"label": "Certification", "value": "EN 15151-2"}, {"label": "Material", "value": "Steel, Polyamide"}, {"label": "Approved rope diameter", "value": "7.1–10 mm"}, {"label": "Weight", "value": "121 g"}]'::jsonb, '["Geometric", "Manual"]'::jsonb, '["slate 663"]'::jsonb, '121 g', '[]'::jsonb, 'EN 15151-2', null, '/images/products/73742.webp', 'BELAY', 'EN 15151-2', '', true, 1),
('71832', 'Jul 2', 'Belay Devices', 'ST', 'Innovative belay device with high braking performance for single ropes. The optimized MEGA JUL geometry ensures easy and secure belaying even with thicker ropes.', '["Body made of high-quality stainless steel", "Optimized geometry ensures easy operation even for beginners", "High braking performance assists the belayer with leader falls", "Rope can be paid out faster to a leader by holding device in the ''open'' position with the thumb", "Perfect handling, even for ropes with a larger diameter", "Suitable for 8.9–11.0 mm single ropes"]'::jsonb, '[{"label": "Certification", "value": "EN 15151-2"}, {"label": "Material", "value": "Steel"}, {"label": "Approved rope diameter", "value": "8.9–11 mm"}, {"label": "Weight", "value": "105 g"}]'::jsonb, '["Made in Germany", "Geometric", "Manual"]'::jsonb, '["oasis 138"]'::jsonb, '105 g', '[]'::jsonb, 'EN 15151-2', 'Made in Germany', '/images/products/71832.webp', 'BELAY', 'EN 15151-2', '', true, 2),
('73831', 'Mega Jul II', 'Belay Devices', 'ST', 'Our versatile, lightweight, and durable stainless steel belay device and descender.', '["Robust solid stainless steel construction", "The increased braking effect of the new device geometry assists the belayer when arresting a fall as a leader", "Faster rope payout when lead climbing thanks to the thumb-loop-based operation", "Additional eyelet for unlocking the device in follower mode using a carabiner", "Suitable for ropes with a diameter of 7.8 to 10.0 mm", "Suitable for belaying a leader, bringing up one or two followers, and rappelling"]'::jsonb, '[{"label": "Certification", "value": "EN 15151-2"}, {"label": "Material", "value": "Steel"}, {"label": "Approved rope diameter", "value": "7.8–10.0 mm"}, {"label": "Weight", "value": "75 g"}]'::jsonb, '["Made in Germany", "Geometric", "Manual"]'::jsonb, '["slate 663"]'::jsonb, '75 g', '[]'::jsonb, 'EN 15151-2', 'Made in Germany', '/images/products/73831.webp', 'BELAY', 'EN 15151-2', '', true, 3),
('73829', 'Ohm II', 'Belay Devices', 'ST', 'The second generation of our innovative and successful OHM is easier to use than ever thanks to a number of updates. The assisted-braking resistor for increasing the braking effect when climbing in rope teams with major weight differences has a swivel joint that improves the device''s freedom of movement. As a result, the clipping direction no longer matters when the device is clipped to the first bolt. The locking system prevents the device from opening accidentally and makes it far easier to insert the rope and remove the device when lowering.', '["OHM is attached at the first bolt in the safety chain", "Rope handling when belaying a lead climber not affected (no additional friction when paying out rope)", "For single ropes from 8.9–11.0 mm", "Far lower forces are exerted on the belayer", "Lowering a heavier person in a controlled manner is far easier", "The device reduces the risk of a collision when falling on the first bolt", "Makes the belayer 25 kg heavier", "Minimum belayer weight: 40 kg"]'::jsonb, '[{"label": "Material", "value": "Aluminium, Steel, Polyamide, LDPE"}, {"label": "Approved rope diameter", "value": "8.9–11 mm"}, {"label": "Weight", "value": "405 g"}]'::jsonb, '["Made in Germany", "Manual"]'::jsonb, '["blue 300", "oasis-night 217", "violet 330"]'::jsonb, '405 g', '[]'::jsonb, null, 'Made in Germany', '/images/products/73829.webp', 'BELAY', '—', '', true, 4),
('73840', 'Ohmega', 'Belay Devices', 'ST', 'Rethink belaying - weighing in at barely 190 g, the compact OHMEGA is a highly versatile brake assistant suitable for use by a wide target group. Whether in climbing gyms, at the crag, or on alpine sport climbing routes (when using a single rope), it offers genuine added value in terms of safety and comfort for both climbers and belayers. This benefits beginners, experienced climbers, and pros as well as rope parties with and without a weight difference. The integrated HMPE sling enables users to switch between three different braking levels with a simple hand movement to suit the weight distribution. The integrated pulley keeps the friction generated at the first bolt lower than when using a quickdraw, so users won''t notice the OHMEGA when climbing or clipping, even on long and difficult routes. Thanks to the short HMPE sling and the resultant minimal activation distance, the belayer finds it easier to belay dynamically and softly, reducing the risk of impact-induced injuries. In the event of a fall, the cam brakes the fall, supporting the belayer and balancing out weight differences. As a result, the belayer won''t be pulled off the ground in the event of a big fall. With falls from a low height, the braking effect of the OHMEGA reduces the risk of both the climbing partners colliding and the climber hitting the ground.', '["Far lower forces are exerted on the belayer", "Versatile brake assistant", "For all rope parties - from beginners to pros", "For climbing gyms, sport climbing crags and alpine sport climbing routes (single rope)", "Lightweight and compact – always in your backpack", "Superior belay assistance", "3 easy-to-adjust braking levels", "Brakes even when falling directly into the device (active load) and reduces the risk of collisions and hitting the ground", "Integrated pulley reduces friction while climbing and clipping, making the device ideal for long, difficult routes"]'::jsonb, '[{"label": "Approved rope diameter", "value": "8.6–10.5 mm"}, {"label": "Weight", "value": "190 g"}]'::jsonb, '["Made in Germany"]'::jsonb, '["oasis 138"]'::jsonb, '190 g', '[]'::jsonb, null, 'Made in Germany', '/images/products/73840.webp', 'BELAY', '—', '', true, 5),
('73838', 'Pinch', 'Belay Devices', 'ST', 'Pinch - a new belaying experience with the PINCH, a new, versatile assisted braking belay device for use in sport climbing, multi-pitch climbing and rope access techniques. The PINCH is the first device on the market that can be attached directly to the central ring of the climbing harness. Thanks to its low, close-to-the-body position, the PINCH does not need to be fixed in place when releasing the rope and the brake rope can always be gripped with all fingers. In addition, the compact belay system provides an increased span, which allows the belayer to pay out 20-30 cm more rope at once. The linear rope run through the frontal steel braking grooves reduces rope tangles when lowering and abseiling. In addition to the lowering lever, the speed can be controlled by the pressure of the braking hand, which contributes to increased braking rope control, especially when using thin, soft ropes. The anti-panic function provides added safety not only for beginners. A special feature is the integrated second braking tier, which enables controlled lowering by pulling the lowering lever further when securing particularly light persons or in systems with high rope friction. Users and experienced rope access technicians can permanently deactivate the anti-panic function using a screw supplied. Another plus: When used on multi-pitch lengths, the PINCH is the only device on the market that can be attached to the belay station in four different directions in 90° increments. This means that the lowering lever can always be brought into a position in which it can be operated freely.', '["Assisted braking belay device for versatile use in sport climbing, multi-pitch climbing and rope access", "Position close to the body due to direct harness attachment increases brake rope control and improves usability", "Direct harness attachment eliminates the risk of cross-loading the belay carabiner", "Deactivatable anti-panic function for increased safety by automatically locking the device if the lowering lever is pulled too far backwards", "Second braking tier if the anti-panic function is activated too frequently due to insufficient load and/or excessive rope friction", "Frontal steel brake grooves allow the rope to run linearly and ensure less rope tangling, increased durability and prevent unsightly discoloration that occurs when the rope rubs against aluminium", "Attachment to the belay station in four different directions in 90° increments", "Equal operation for right and left-handed users", "Suitable for dynamic ropes from 8.5 to 10.5 mm diameter", "Suitable for static ropes from 10.0 to 10.5 mm diameter (120 kg max. user weight)"]'::jsonb, '[{"label": "Certification", "value": "EN 15151-1, EN 12841-C, UIAA 129"}, {"label": "Material", "value": "Steel/ALU"}, {"label": "Approved rope diameter", "value": "8.5–10.5 mm"}, {"label": "Weight", "value": "235 g"}]'::jsonb, '["UIAA", "Mechanical"]'::jsonb, '["anthracite-oasis 815", "blue-night 314", "night 017", "violet-oasis 296"]'::jsonb, '235 g', '[]'::jsonb, 'EN 15151-1', null, '/images/products/73838.webp', 'BELAY', 'EN 15151-1', '', true, 6),
('73946', 'Spare Ohmega Sling', 'Belay Devices', 'ST', 'Replacement sling for the EDELRID OHMEGA.', '[]'::jsonb, '[{"label": "Certification", "value": "EN 566"}, {"label": "Material", "value": "HMPE"}, {"label": "Minimum breaking strength", "value": "22 kN"}, {"label": "Weight", "value": "5 g"}]'::jsonb, '["Fair Wear"]'::jsonb, '["night 017"]'::jsonb, '5 g', '[]'::jsonb, 'EN 566', null, '/images/products/73946.webp', 'BELAY', 'EN 566', '', true, 7),
('73731', 'Antitwist', 'Carabiners & Quickdraws', 'V10', 'The ANTITWIST fixes the lower carabiner and sling preventing unwanted rotation of the biner during use. Available for webbing with a width of 11 and 16 mm. Package contents: 10 pcs.', '[]'::jsonb, '[{"label": "Material", "value": "TPU"}]'::jsonb, '[]'::jsonb, '["night 017", "oasis 138"]'::jsonb, null, '[{"length": "11 MM", "weight": "30g"}, {"length": "16 MM", "weight": "30g"}]'::jsonb, null, null, '/images/products/73731.webp', 'QUICKDRAW', '—', '', true, 8),
('88271', 'Axiom', 'Carabiners & Quickdraws', 'ST', 'Carabiner with integrated pulley in the spine. The pulley reduces rope friction to a minimum and maintains its function even under load. The optimized design of the AXIOM ensures that the rope is always ideally guided so that it can always run on the pulley. Available with a classic gate or the automatic and very compact Slider locking gate. The gate opens on the pulley side, which makes installing the rope easier.', '["Very lightweight construction", "Available as a gate or slider version", "Pulley maintains its function even under load", "Optimized design for perfect rope guidance in the carabiner at all times", "Efficiency: 86 %"]'::jsonb, '[{"label": "Certification", "value": "EN 12275"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "Normal"}, {"label": "Carabiner shape", "value": "Axiom"}, {"label": "Fmax. major axis", "value": "22 kN"}, {"label": "Fmax. open", "value": "7 kN"}, {"label": "Fmax. minor axis", "value": "8 kN"}, {"label": "Width", "value": "65 mm"}, {"label": "Length", "value": "100 mm"}, {"label": "Gate opening", "value": "18 mm"}, {"label": "Weight", "value": "66g"}]'::jsonb, '[]'::jsonb, '["icemint 329"]'::jsonb, '66g', '[]'::jsonb, 'EN 12275', null, '/images/products/88271.webp', 'CARABINER', 'EN 12275', '', true, 9),
('88272', 'Axiom Slider', 'Carabiners & Quickdraws', 'ST', 'Carabiner with integrated pulley in the spine. The pulley reduces rope friction to a minimum and maintains its function even under load. The optimized design of the AXIOM ensures that the rope is always ideally guided so that it can always run on the pulley. Available with a classic gate or the automatic and very compact Slider locking gate. The gate opens on the pulley side, which makes installing the rope easier.', '["Very lightweight construction", "Available as a gate or slider version", "Pulley maintains its function even under load", "Optimized design for perfect rope guidance in the carabiner at all times", "Efficiency: 86 %"]'::jsonb, '[{"label": "Certification", "value": "EN 12275 / EN 362"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "Slider"}, {"label": "Carabiner shape", "value": "Axiom"}, {"label": "Fmax. major axis", "value": "22 kN"}, {"label": "Fmax. open", "value": "7 kN"}, {"label": "Fmax. minor axis", "value": "8 kN"}, {"label": "Width", "value": "65 mm"}, {"label": "Length", "value": "100 mm"}, {"label": "Gate opening", "value": "18 mm"}, {"label": "Weight", "value": "68g"}]'::jsonb, '[]'::jsonb, '["oasis 138"]'::jsonb, '68g', '[]'::jsonb, 'EN 12275 / EN 362', null, '/images/products/88272.webp', 'CARABINER', 'EN 12275 / EN 362', '', true, 10),
('73811', 'Bulletproof Screw', 'Carabiners & Quickdraws', 'ST', 'Small, robust screwgate biner with steel insert at the apex. Prevents premature wear and burrs or sharp edges. Ideal for personal protection use, e.g. clipping into a belay anchor.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "H-profile construction ensures best possible use of material and minimal weight", "Steel insert prevents premature wear from rope friction or bolt hangers"]'::jsonb, '[{"label": "Certification", "value": "EN 12275 / UIAA 121"}, {"label": "Material", "value": "Alu / Steel"}, {"label": "Closure", "value": "Screw"}, {"label": "Carabiner shape", "value": "Offset D Bulletproof"}, {"label": "Fmax. major axis", "value": "27 kN"}, {"label": "Fmax. open", "value": "8 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "60 mm"}, {"label": "Length", "value": "100 mm"}, {"label": "Gate opening", "value": "18 mm"}, {"label": "Weight", "value": "60g"}]'::jsonb, '["Keylock"]'::jsonb, '["icemint 329", "oasis 138"]'::jsonb, '60g', '[]'::jsonb, 'EN 12275 / UIAA 121', null, '/images/products/73811.webp', 'CARABINER', 'EN 12275 / UIAA 121', '', true, 11),
('73805', 'HMS Bruce Steel Screw FG II', 'Carabiners & Quickdraws', 'ST', 'Extremely strong steel HMS carabiner with an internal spring bar to prevent it from twisting. Ideal for situations with greater wear (belaying with a tubular belay device or top-roping).', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "Spring bar holds the carabiner in place when belaying to prevent cross loading", "H-profile construction ensures best possible use of material and minimal weight", "The HMS BRUCE STEEL FG is designed to perfectly complement the MEGA JUL''s geometry"]'::jsonb, '[{"label": "Certification", "value": "EN 12275 / EN 362"}, {"label": "Material", "value": "Steel"}, {"label": "Closure", "value": "Screw"}, {"label": "Fmax. major axis", "value": "28 kN"}, {"label": "Fmax. open", "value": "10 kN"}, {"label": "Fmax. minor axis", "value": "8 kN"}, {"label": "Width", "value": "72 mm"}, {"label": "Length", "value": "107 mm"}, {"label": "Gate opening", "value": "22 mm"}, {"label": "Weight", "value": "140g"}]'::jsonb, '["Keylock"]'::jsonb, '["silver 006"]'::jsonb, '140g', '[]'::jsonb, 'EN 12275 / EN 362', null, '/images/products/73805.webp', 'CARABINER', 'EN 12275 / EN 362', '', true, 12),
('73807', 'HMS Bruce Steel Triple FG', 'Carabiners & Quickdraws', 'ST', 'Extremely strong steel HMS carabiner with an internal spring bar to prevent it from twisting. Ideal for situations with greater wear (belaying with a tubular belay device or top-roping).', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "Available as either screwgate or Triple Lock model", "Spring bar holds the carabiner in place when belaying to prevent cross loading", "H-profile construction ensures best possible use of material and minimal weight", "Designed to perfectly complement the geometry of belay devices from the Jul family"]'::jsonb, '[{"label": "Certification", "value": "EN 12275 / EN 362"}, {"label": "Material", "value": "Steel"}, {"label": "Closure", "value": "Triple"}, {"label": "Fmax. major axis", "value": "28 kN"}, {"label": "Fmax. open", "value": "10 kN"}, {"label": "Fmax. minor axis", "value": "8 kN"}, {"label": "Width", "value": "72 mm"}, {"label": "Length", "value": "107 mm"}, {"label": "Gate opening", "value": "22 mm"}, {"label": "Weight", "value": "142g"}]'::jsonb, '["Keylock"]'::jsonb, '["icemint 329"]'::jsonb, '142g', '[]'::jsonb, 'EN 12275 / EN 362', null, '/images/products/73807.webp', 'CARABINER', 'EN 12275 / EN 362', '', true, 13),
('73760', 'HMS Bullet PermaLock', 'Carabiners & Quickdraws', 'ST', 'Innovative screw gate carabiner with an additional locking mechanism on the locking sleeve. This is made possible by the smart PERMALOCK locking mechanism. Due to the integrated pressure lock, the rotating locking sleeve of the carabiner gate can be blocked and is thus secured against unintentional opening. Thus the HMS BULLET PERMALOCK combines the safety of a locking carabiner, according to category 3 of the German Alpine Club (DAV) provisions, with the user-friendliness of a normal screw or snap carabiner.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "H-profile construction ensures best possible use of material and minimal weight", "Locking carabiner, according to category 3 of the German Alpine Club (DAV) provisions on locking carabiners", "Red indicator on the gate shows whether the carabiner is completely closed", "Improved safety combined with the customary ease of use of a regular screw gate carabiner"]'::jsonb, '[{"label": "Certification", "value": "EN 12275; EN 362"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "PermaLock"}, {"label": "Carabiner shape", "value": "HMS"}, {"label": "Fmax. major axis", "value": "26 kN"}, {"label": "Fmax. open", "value": "9 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "75 mm"}, {"label": "Length", "value": "110 mm"}, {"label": "Gate opening", "value": "24 mm"}, {"label": "Weight", "value": "75g"}]'::jsonb, '[]'::jsonb, '["night 017", "silver 006"]'::jsonb, '75g', '[]'::jsonb, 'EN 12275; EN 362', null, '/images/products/73760.webp', 'CARABINER', 'EN 12275; EN 362', '', true, 14),
('73816', 'HMS Bullet Screw', 'Carabiners & Quickdraws', 'ST', 'Robust HMS carabiner with Keylock closure. Ideal for use with EDELRID belay devices.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "Available as either screwgate or Triple Lock model", "H-profile construction ensures best possible use of material and minimal weight"]'::jsonb, '[{"label": "Certification", "value": "EN 12275; EN 362"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "Screw"}, {"label": "Carabiner shape", "value": "HMS"}, {"label": "Fmax. major axis", "value": "26 kN"}, {"label": "Fmax. open", "value": "9 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "75 mm"}, {"label": "Length", "value": "110 mm"}, {"label": "Gate opening", "value": "24 mm"}, {"label": "Weight", "value": "74g"}]'::jsonb, '[]'::jsonb, '["black 010", "oasis 138"]'::jsonb, '74g', '[]'::jsonb, 'EN 12275; EN 362', null, '/images/products/73816.webp', 'CARABINER', 'EN 12275; EN 362', '', true, 15),
('73763', 'HMS Bullet Screw RFID', 'Carabiners & Quickdraws', 'ST', 'The robust HMS carabiner HMS BULLET with integrated RFID chip. This makes the operational documentation of the equipment child''s play.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "H-profile construction ensures best possible use of material and minimal weight"]'::jsonb, '[{"label": "Certification", "value": "EN 362; EN 12275 H"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "Screw"}, {"label": "Carabiner shape", "value": "HMS"}, {"label": "Fmax. major axis", "value": "26 kN"}, {"label": "Fmax. open", "value": "9 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "75 mm"}, {"label": "Length", "value": "110 mm"}, {"label": "Gate opening", "value": "24 mm"}, {"label": "Weight", "value": "74g"}]'::jsonb, '["RFID"]'::jsonb, '["oasis 138"]'::jsonb, '74g', '[]'::jsonb, 'EN 362; EN 12275 H', null, '/images/products/73763.webp', 'CARABINER', 'EN 362; EN 12275 H', '', true, 16),
('73817', 'HMS Bullet Triple', 'Carabiners & Quickdraws', 'ST', 'Robust HMS carabiner with Keylock closure. Ideal for use with EDELRID belay devices.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "Available as either screwgate or Triple Lock model", "H-profile construction ensures best possible use of material and minimal weight"]'::jsonb, '[{"label": "Certification", "value": "EN 12275; EN 362"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "Triple"}, {"label": "Carabiner shape", "value": "HMS"}, {"label": "Fmax. major axis", "value": "26 kN"}, {"label": "Fmax. open", "value": "9 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "75 mm"}, {"label": "Length", "value": "110 mm"}, {"label": "Gate opening", "value": "24 mm"}, {"label": "Weight", "value": "79g"}]'::jsonb, '[]'::jsonb, '["icemint 329", "silver 006"]'::jsonb, '79g', '[]'::jsonb, 'EN 12275; EN 362', null, '/images/products/73817.webp', 'CARABINER', 'EN 12275; EN 362', '', true, 17),
('73764', 'HMS Bullet Triple RFID', 'Carabiners & Quickdraws', 'ST', 'The robust HMS carabiner HMS BULLET with integrated RFID chip. This makes the operational documentation of the equipment child''s play.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "H-profile construction ensures best possible use of material and minimal weight"]'::jsonb, '[{"label": "Certification", "value": "EN 362; EN 12275 H"}, {"label": "Material", "value": "Aluminium"}, {"label": "Closure", "value": "Triple"}, {"label": "Carabiner shape", "value": "HMS"}, {"label": "Fmax. major axis", "value": "26 kN"}, {"label": "Fmax. open", "value": "9 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "75 mm"}, {"label": "Length", "value": "110 mm"}, {"label": "Gate opening", "value": "24 mm"}, {"label": "Weight", "value": "74g"}]'::jsonb, '["RFID"]'::jsonb, '["icemint 329"]'::jsonb, '74g', '[]'::jsonb, 'EN 362; EN 12275 H', null, '/images/products/73764.webp', 'CARABINER', 'EN 362; EN 12275 H', '', true, 18),
