('73806', 'Screwlink 8mm II', 'Carabiners & Quickdraws', 'ST', 'Certified oval steel screw link.', '[]'::jsonb, '[{"label": "Material", "value": "Steel"}, {"label": "Closure", "value": "Screw"}, {"label": "Carabiner shape", "value": "Oval"}, {"label": "Fmax. major axis", "value": "55 kN"}, {"label": "Fmax. open", "value": "35 kN"}, {"label": "Fmax. minor axis", "value": "10 kN"}, {"label": "Width", "value": "36 mm"}, {"label": "Length", "value": "73 mm"}, {"label": "Weight", "value": "77g"}]'::jsonb, '[]'::jsonb, '["silver 006"]'::jsonb, '77g', '[]'::jsonb, 'EN 12275, EN 362', null, '/images/products/73806.webp', 'STEEL LINK', 'EN 12275, EN 362', '', true, 47),
('88291', 'Steel HMS Screw', 'Carabiners & Quickdraws', 'ST', 'HMS carabiner made of hardened steel for maximum protection. Ideal for top roping, outdoor centres, high ropes courses, climbing gyms or for other uses where a regular strain is placed on the carabiner.', '["Keylock closure mechanism for optimum handling when clipping and unclipping", "Brass sleeve ensures optimum gate strength"]'::jsonb, '[{"label": "Certification", "value": "EN 12275 / EN 362 / UIAA 121"}, {"label": "Material", "value": "Steel"}, {"label": "Closure", "value": "Screw"}, {"label": "Carabiner shape", "value": "HMS"}, {"label": "Fmax. major axis", "value": "40 kN"}, {"label": "Fmax. open", "value": "15 kN"}, {"label": "Fmax. minor axis", "value": "15 kN"}, {"label": "Width", "value": "74 mm"}, {"label": "Length", "value": "110 mm"}, {"label": "Gate opening", "value": "23 mm"}, {"label": "Weight", "value": "236g"}]'::jsonb, '["Keylock"]'::jsonb, '["silver 006"]'::jsonb, '236g', '[]'::jsonb, 'EN 12275 / EN 362 / UIAA 121', null, '/images/products/88291.webp', 'CARABINER', 'EN 12275 / EN 362 / UIAA 121', '', true, 48),
('D100TA41S000C', 'Ambition 10.0 - Red', 'Ropes', null, 'A rope made for beginners. Its sturdy design inspires confidence and rightly so, as it boasts a high number of falls and its durability is further enhanced by the SBS braid system, which ensures less friction and a smoother, but thanks to the larger diameter, slower passage in the belay. When climbing becomes a passion, there''s no better choice. With rope you''ll appreciate:', '["High durability", "SBS braid", "Suitable for beginners"]'::jsonb, '[{"label": "Rope diameter (mm)", "value": "10"}, {"label": "Weight (g/m)", "value": "67"}, {"label": "Number of UIAA falls", "value": "9"}, {"label": "Max impact force (kN)", "value": "8.9"}, {"label": "Sheath slippage (%)", "value": "0.2"}, {"label": "Static elongation (%)", "value": "5"}, {"label": "Dynamic elongation (%)", "value": "33"}, {"label": "Knotability", "value": "1"}, {"label": "Number of bobbins", "value": "40"}, {"label": "Sheath mass", "value": "38 %"}, {"label": "CE 1019", "value": "yes"}, {"label": "EN 892", "value": "yes"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, null, '[]'::jsonb, 'EN 892 / UIAA', 'TENDON — Czech Republic', '/images/products/D100TA41S000C.webp', 'TENDON', 'EN 892 / UIAA', 'mytendon.com', true, 49),
('FR444032', 'Fast Rope', 'Ropes', null, 'In the production of the unique Fast Rope, special PA BCF fibres are used which give superior protection during descending, having high resistance to wear and rupture. The rope with a diameter of 44 mm and a unique construction offers the user good control during descending without additional belay. We are able to supply our key military clients in many countries with Fast Ropes also in diameters 40 mm and 32 mm. • spliced eye with high strength and resistance, for frequent straining and loading (e.g. in practising). • eye made of express slings (ST-short termination) – lightweight and especially short eye with high strenght. Easy examination of seams and express slings after removal of the protector. In emergency the rope may be simply cut at the termination. • eye with metal termination (MT-metal termination) for different types of metal connectors and hooks.', '[]'::jsonb, '[{"label": "Rope diameter, pre-tensioned according to EN ISO 2307 (245 kg) (mm)", "value": "44 / 40 / 32"}, {"label": "Rope diameter, loose (zero tension) (mm)", "value": "50 / 46 / 38"}, {"label": "Rope weight, pre-tensioned according to EN 2307 (245 kg) (kg/100 m)", "value": "77 / 60 / 42"}, {"label": "Rope weight, loose (zero tension) (kg/100 m)", "value": "96 / 75 / 52"}, {"label": "Minimum rope strenght with spliced eye (kg)", "value": "12000 / 10000 / 7500"}, {"label": "Minimum rope strenght with sewn loop with textile protection (kg)", "value": "6000 / 6000 / 6000"}, {"label": "Minimum rope strenght with steel termination (kg)", "value": "3000 / 3000 / -"}, {"label": "Minimum strenght of suspension sling (F.R.I.E.S.) (kg)", "value": "2500 / 2500 / 2500"}, {"label": "Rope elongation, pre-tensioned according to EN ISO 2307 (245 kg) (%)", "value": "25 / 25 / 25"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, null, '[]'::jsonb, null, 'TENDON — Czech Republic', '/images/products/FR444032.webp', 'TENDON', '—', 'mytendon.com', true, 50),
('D110TT42S000C', 'Trust 11.0 - Yellow', 'Ropes', null, 'The thickest rope in our portfolio of dynamic ropes. The mix of its parameters together creates a robust and safe rope with high durability and extremely long life. This rope is most often found in rope centres or other climbing schools. With this rope you will appreciate:', '["Durability", "Safety"]'::jsonb, '[{"label": "Rope diameter (mm)", "value": "11"}, {"label": "Weight (g/m)", "value": "79"}, {"label": "Number of UIAA falls", "value": "16"}, {"label": "Max impact force (kN)", "value": "9.1"}, {"label": "Sheath slippage (%)", "value": "0.4"}, {"label": "Static elongation (%)", "value": "5.3"}, {"label": "Dynamic elongation (%)", "value": "31"}, {"label": "Knotability", "value": "1"}, {"label": "Number of bobbins", "value": "48"}, {"label": "Sheath mass", "value": "39,4 %"}, {"label": "CE 1019", "value": "yes"}, {"label": "EN 892", "value": "yes"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, null, '[]'::jsonb, 'EN 892 / UIAA', 'TENDON — Czech Republic', '/images/products/D110TT42S000C.webp', 'TENDON', 'EN 892 / UIAA', 'mytendon.com', true, 51),
('85401', 'Flux', 'Pulleys', 'ST', 'The FLUX is a small, practical, ball-bearing pulley for block and tackles as well as directional anchors with fabric ropes and medium loads. The movable side pieces enable quick and easy installation. The large carabiner hole fits all conventional EDELRID carabiners.', '["Compact, lightweight construction", "Flexible side pieces for easy rigging and removal", "Ball-bearing-mounted pulley for high efficiency", "Roller made from anodized aluminum"]'::jsonb, '[{"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "50 mm"}, {"label": "Height", "value": "75 mm"}, {"label": "Efficiency", "value": "94 %"}, {"label": "Working Load Limit", "value": "500 kg"}, {"label": "Approved rope diameter", "value": "6 - 13 mm"}, {"label": "Minimum breaking strength", "value": "26 kN"}, {"label": "Weight", "value": "96g"}]'::jsonb, '[]'::jsonb, '["icemint 329"]'::jsonb, '96g', '[]'::jsonb, 'EN 12278', null, '/images/products/85401.webp', 'PULLEY', 'EN 12278', '', true, 52),
('85400', 'Neelix', 'Pulleys', 'ST', 'The NEELIX is a small, robust pulley with fixed side pieces. The ball-bearing-mounted pulley offers outstanding efficiency and is multifunctional, for example for tree care or use in cable car systems. The spacer provided prevents the side pieces from drawing together when used with ropes or slings.', '["Compact, lightweight construction", "Ball-bearing-mounted pulley for high efficiency", "Roller made from anodized aluminum"]'::jsonb, '[{"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "48 mm"}, {"label": "Height", "value": "99 mm"}, {"label": "Efficiency", "value": "94 %"}, {"label": "Working Load Limit", "value": "600 kg"}, {"label": "Approved rope diameter", "value": "6 - 13 mm"}, {"label": "Minimum breaking strength", "value": "30 kN"}, {"label": "Weight", "value": "122g"}]'::jsonb, '[]'::jsonb, '["icemint 329"]'::jsonb, '122g', '[]'::jsonb, 'EN 12278', null, '/images/products/85400.webp', 'PULLEY', 'EN 12278', '', true, 53),
('85403', 'Pike Rescue', 'Pulleys', 'ST', 'The PIKE RESCUE is a large pulley used in simple and more complex block and tackle systems for rescue operations. It has a particularly high breaking load. The large carabiner opening offers enough space for two carabiners while a locking carabiner with a gate can be fully rotated in it.', '["Ball-bearing-mounted pulley for high efficiency", "Rollers made from anodized aluminum", "Eyelet for up to two carabiners", "Larger wrap angle"]'::jsonb, '[{"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "72 mm"}, {"label": "Height", "value": "120 mm"}, {"label": "Efficiency", "value": "98 %"}, {"label": "Working Load Limit", "value": "900 kg"}, {"label": "Approved rope diameter", "value": "6 - 13 mm"}, {"label": "Minimum breaking strength", "value": "46 kN"}, {"label": "Weight", "value": "262g"}]'::jsonb, '[]'::jsonb, '["anthracite 069"]'::jsonb, '262g', '[]'::jsonb, 'EN 12278', null, '/images/products/85403.webp', 'PULLEY', 'EN 12278', '', true, 54),
('85404', 'Pike Rescue Double', 'Pulleys', 'ST', 'The PIKE RESCUE DOUBLE is a large double pulley used in simple and more complex block and tackle systems for rescue operations. It has a particularly high breaking load. The large eyelet at the top can fit two carabiners while a further carabiner can be clipped into the lower eyelet.', '["Rollers made from anodized aluminum", "Larger wrap angle", "Two ball-bearing-mounted rollers for high efficiency", "Top eyelet for two carabiners and bottom eyelet for one carabiner"]'::jsonb, '[{"label": "Certification", "value": "EN 12278"}, {"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "78 mm"}, {"label": "Height", "value": "150 mm"}, {"label": "Efficiency", "value": "98 %"}, {"label": "Working Load Limit", "value": "900 kg"}, {"label": "Approved rope diameter", "value": "6 - 13 mm"}, {"label": "Minimum breaking strength", "value": "46 kN"}, {"label": "Weight", "value": "461g"}]'::jsonb, '[]'::jsonb, '["anthracite 069"]'::jsonb, '461g', '[]'::jsonb, 'EN 12278', null, '/images/products/85404.webp', 'PULLEY', 'EN 12278', '', true, 55),
('85405', 'Puck', 'Pulleys', 'ST', 'Special pulley for tree care. Suitable for use either in friction hitch systems or as a rigging plate with a pulley if multiple anchor points are required. The rounded edges make it particularly gentle on ropes. Ideal for auxiliary cable cars, block and tackle systems, or rigging systems.', '["Compact, lightweight construction", "Ball-bearing-mounted pulley for high efficiency", "Roller made from anodized aluminum", "Special tree care pulley"]'::jsonb, '[{"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "68 mm"}, {"label": "Height", "value": "98 mm"}, {"label": "Efficiency", "value": "94 %"}, {"label": "Working Load Limit", "value": "800 kg"}, {"label": "Approved rope diameter", "value": "< 13 mm"}, {"label": "Minimum breaking strength", "value": "40 kN"}, {"label": "Weight", "value": "164g"}]'::jsonb, '[]'::jsonb, '["icemint 329"]'::jsonb, '164g', '[]'::jsonb, 'EN 12278', null, '/images/products/85405.webp', 'PULLEY', 'EN 12278', '', true, 56),
('73743', 'Spoc', 'Pulleys', 'ST', 'Ultra-light pulley with backstop. Designed for lifting loads, crevasse rescue operations, or as an emergency ascender.', '["The backstop can be fixed in the open position in order to use the device as a simple pulley", "Pulley diameter: 20 mm", "Ball bearing pulleys for high efficiency (92 %)", "Cams for optimal grip on iced or muddy ropes", "Suitable for ropes with a diameter of 7.0 to 11.0 mm as well as for the EDELRID RAP LINE"]'::jsonb, '[{"label": "Material", "value": "Aluminium, Steel, Polyamide"}, {"label": "Minimum breaking strength", "value": "15 kN"}, {"label": "Weight", "value": "60g"}]'::jsonb, '["Made in Germany", "Technologies"]'::jsonb, '["oasis 138"]'::jsonb, '60g', '[]'::jsonb, 'EN 12278, EN 567', 'Made in Germany', '/images/products/73743.webp', 'PULLEY', 'EN 12278, EN 567', '', true, 57),
('85402', 'Warp', 'Pulleys', 'ST', 'The WARP is a highly efficient, ball-bearing double pulley. Made from stainless steel, the wear-resistant rollers are optimized for use with steel ropes but also work perfectly in systems with fabric ropes. The large opening offers enough space for two carabiners. The connection point at the top enables use in a redundant system with double rope guidance. The WARP is primarily intended for use in adventure parks and on auxiliary cable cars.', '["Stainless steel rollers", "Ball-bearing double pulley for outstanding efficiency", "Large attachment eyelet for two carabiners", "Top eyelet enables double rope guidance as a redundant system"]'::jsonb, '[{"label": "Certification", "value": "EN 12278"}, {"label": "Material", "value": "Aluminium/Steel"}, {"label": "Width", "value": "100 mm"}, {"label": "Height", "value": "85 mm"}, {"label": "Efficiency", "value": "92 %"}, {"label": "Working Load Limit", "value": "1000 kg"}, {"label": "Approved rope diameter", "value": "< 13 mm"}, {"label": "Minimum breaking strength", "value": "32 kN"}, {"label": "Weight", "value": "303g"}]'::jsonb, '[]'::jsonb, '["oasis 138"]'::jsonb, '303g', '[]'::jsonb, 'EN 12278', null, '/images/products/85402.webp', 'PULLEY', 'EN 12278', '', true, 58),
('88250', 'Foot Cruiser right', 'Rope Clamps & Ascenders', 'ST', 'Sophisticated foot ascender that enables efficient and low-fatigue climbing on the rope. A pre-installed but removable rope safety device prevents unintentional release. The locking mechanism of the FOOT CRUISER is easy to operate - even with your feet. The ascent loop is fitted with an abrasion protector. The FOOT CRUISER is available for right or left feet.', '["For 8.0–13.0 mm diameter kernmantle ropes", "Cam with self-cleaning slots for optimum grip on frozen or muddy ropes", "Pre-installed but removable rope safety device to prevent unintentional release", "Ascent loop fitted with abrasion protector"]'::jsonb, '[{"label": "Material", "value": "Aluminium"}, {"label": "Approved rope diameter", "value": "8 - 13mm"}, {"label": "Weight", "value": "105g"}]'::jsonb, '[]'::jsonb, '["night 017"]'::jsonb, '105g', '[]'::jsonb, null, null, '/images/products/88250.webp', 'ASCENDER', '—', '', true, 59),
('88253', 'Hand Cruiser Left', 'Rope Clamps & Ascenders', 'ST', 'Ergonomically shaped hand ascender for a comfortable ascent on the rope. The curved design increases comfort and reduces friction in the system. A large eyelet allows several carabiners to be attached; a smaller eyelet slightly higher is ideal for setting up a directional anchor. Besides, the secondary hand can comfortably grasp the HAND CRUISER at the top during ascent.', '["For 8.0–13.0 mm diameter kernmantle ropes", "Right-hand/left-hand version in different colors for easy identification", "Cams for optimal grip on iced or muddy ropes", "The upper part of the ascender can be grasped with the other hand for two-handed ascents"]'::jsonb, '[{"label": "Certification", "value": "EN 12841-B; EN 567"}, {"label": "Approved rope diameter", "value": "8 - 13 mm"}, {"label": "Weight", "value": "200g"}]'::jsonb, '[]'::jsonb, '["silver 006"]'::jsonb, '200g', '[]'::jsonb, 'EN 12841-B; EN 567', null, '/images/products/88253.webp', 'ASCENDER', 'EN 12841-B; EN 567', '', true, 60),
('88254', 'Hand Cruiser Right', 'Rope Clamps & Ascenders', 'ST', 'Ergonomically shaped hand ascender for a comfortable ascent on the rope. The curved design increases comfort and reduces friction in the system. A large eyelet allows several carabiners to be attached; a smaller eyelet slightly higher is ideal for setting up a directional anchor. Besides, the secondary hand can comfortably grasp the HAND CRUISER at the top during ascent.', '["For 8.0–13.0 mm diameter kernmantle ropes", "Right-hand/left-hand version in different colors for easy identification", "Cams for optimal grip on iced or muddy ropes", "The upper part of the ascender can be grasped with the other hand for two-handed ascents"]'::jsonb, '[{"label": "Certification", "value": "EN 12841-B; EN 567"}, {"label": "Approved rope diameter", "value": "8 - 13 mm"}, {"label": "Weight", "value": "200g"}]'::jsonb, '[]'::jsonb, '["night 017"]'::jsonb, '200g', '[]'::jsonb, 'EN 12841-B; EN 567', null, '/images/products/88254.webp', 'ASCENDER', 'EN 12841-B; EN 567', '', true, 61),
('88332', 'Megawatt', 'Descenders & Rescue', 'ST', 'MEGAWATT is a universal descender device for industrial climbers and rescue operations with a payload of up to 230 kg. The intelligent transmission mechanics of the descent lever facilitate a large operating range and exact adjustment of the speed at minimum force. The short lever always automatically returns to the parking position and makes the device extremely compact. This prevents entanglement. The ergonomic lever design with rubber coated grip inserts allows intuitive active and passive operation with the left or right hand. The four-way safety lock allows inserting the rope without having to separate the device from the karabiner. Steel inserts in the especially burdened spots increase the service life of the device. The risk of uncontrolled travel along the rope is reduced by the anti-panic function. It can also be triggered deliberately to reverse the sense of operation of the lever. This allows optimum handling in any application and position. All this makes the MEGAWATT the most versatile descender device in the market at a weight of only 495 g.', '["Steel inserts on the abrasion-prone areas increase service life", "Precision operation of the lever at minimum exertion", "Short lever and compact design prevent entanglement", "Automatic parking position of the control lever", "Ergonomic lever with rubber-coated grip inserts for intuitive handling with the left or right hand in active and passive applications", "Four-way safety lock allows inserting the rope without having to separate the device from the karabiner", "Large karabiner hole allows 360° rotation of the karabiner", "Anti-panic function reduces the risk of uncontrolled descent movements and creates additional operating options", "Interlocking bolt supplied with the lever allows use as a closed system", "Descent of heavy loads of up to 230 kg", "For a rope diameter of 8.9 to 11.8 mm", "Meets the standards EN 12841-C, EN 341-2A, EN 15151-1/8 and ANSI/ASSE Z359.4", "Integrated NFC chip for simplified operational documentation"]'::jsonb, '[{"label": "Certification", "value": "EN 12841-C, EN 341-2A, ANSI/ASSE Z359.4, EN 15151-1/8"}, {"label": "Approved rope diameter", "value": "8,9-11,8mm"}, {"label": "Weight", "value": "495g"}]'::jsonb, '["NFC", "Anti-panic", "Technologies"]'::jsonb, '["night 017"]'::jsonb, '495g', '[]'::jsonb, 'EN 12841-C, EN 341-2A, ANSI/ASSE Z359.4, EN 15151-1/8', null, '/images/products/88332.webp', 'RESCUE', 'EN 12841-C, EN 341-2A, ANSI/ASSE Z359.4, EN 15151-1/8', '', true, 62),
('88920', 'Rescue 8', 'Descenders & Rescue', 'ST', 'Large aluminium descender with ears for belay, descent and positioning.', '[]'::jsonb, '[{"label": "Certification", "value": "EN 15151-2"}, {"label": "Material", "value": "Aluminium"}, {"label": "Width", "value": "170mm"}, {"label": "Length", "value": "170mm"}, {"label": "Approved rope diameter", "value": "7,8 - 12,0mm"}, {"label": "Weight", "value": "240g"}]'::jsonb, '[]'::jsonb, '["blue 300", "night 017"]'::jsonb, '240g', '[]'::jsonb, 'EN 15151-2', null, '/images/products/88920.webp', 'RESCUE', 'EN 15151-2', '', true, 63),
('74942', 'Joker III', 'Harnesses', 'ST', 'The JOKER is a highly adjustable sit harness with a polyamide central ring that is ideal for courses and rental usage. The harness is primarily made from polyester, which makes it particularly robust and durable. For enhanced safety during rental usage, the gear loop is made from load-bearing material.', '["Stitched webbing terminations designed so that straps cannot be completely unthreaded", "Integrated RFID-Chip", "Classic design made from 45 mm polyester webbing", "Central ring made from polyamide", "Slide Block buckles on the waist belt and leg loops offer infinite adjustability and make the harness easy to put on and take off", "Right/left leg loop markings and replaceable, elasticated bum straps make it easier to put on the harness correctly", "Red wear indicator in all load-bearing straps on the waist belt and leg loops", "High-strength gear loop for additional safety in the rental sector"]'::jsonb, '[{"label": "Material", "value": "Polyester"}, {"label": "Weight", "value": "485g"}]'::jsonb, '["UIAA", "Indicator", "Adjustable leg loops", "Fair Wear", "Technologies"]'::jsonb, '["night-oasis 219"]'::jsonb, '485g', '[]'::jsonb, 'EN 12277 Typ C, UIAA 105', null, '/images/products/74942.webp', 'HARNESS', 'EN 12277 Typ C, UIAA 105', '', true, 64),
('74943', 'Joker Junior III', 'Harnesses', 'ST', 'The JOKER JUNIOR is a highly adjustable sit harness with a polyamide central ring that is ideal for courses and rental usage. The harness is primarily made from polyester, which makes it particularly robust and durable. For enhanced safety during rental usage, the gear loop is made from load-bearing material.', '["Stitched webbing terminations designed so that straps cannot be completely unthreaded", "Integrated RFID-Chip", "Classic design made from 45 mm polyester webbing", "Central ring made from polyamide", "Slide Block buckles on the waist belt and leg loops offer infinite adjustability and make the harness easy to put on and take off", "Right/left leg loop markings and replaceable, elasticated bum straps make it easier to put on the harness correctly", "Red wear indicator in all load-bearing straps on the waist belt and leg loops", "High-strength gear loop for additional safety in the rental sector"]'::jsonb, '[{"label": "Material", "value": "100% Polyester"}, {"label": "Weight", "value": "410g"}]'::jsonb, '["UIAA", "Indicator", "Kids", "Adjustable leg loops", "Fair Wear", "Technologies"]'::jsonb, '["night-icemint 749"]'::jsonb, '410g', '[]'::jsonb, 'EN 12277 Typ C, UIAA 105', null, '/images/products/74943.webp', 'HARNESS', 'EN 12277 Typ C, UIAA 105', '', true, 65),
('72050', 'Ultralight Junior III', 'Helmets', 'ST', 'The Junior version of the ULTRALIGHT has also had a make-over. It provides the same features as the ULTRALIGHT.', '["Extremely robust and impact-resistant polypropylene shell", "Headlamp attachment option", "Fully adjustable, replaceable, and washable head and chin strap for optimum fit", "Various vents for continuous air exchange", "One size: fits a head circumference of 48–58 cm", "Comfortably padded carrying system with antibacterial webbing"]'::jsonb, '[{"label": "Certification", "value": "EN 12492, UIAA 106"}, {"label": "Material", "value": "EPS, Polypropylen, Polaymide, PU leather"}, {"label": "Head size", "value": "48 - 58"}, {"label": "Weight", "value": "380g"}]'::jsonb, '["UIAA", "Kids"]'::jsonb, '["icemint 329", "red 200", "snow 047"]'::jsonb, '380g', '[]'::jsonb, 'EN 12492, UIAA 106', null, '/images/products/72050.webp', 'HELMET', 'EN 12492, UIAA 106', '', true, 66),
('74341', 'Cable Kit VI', 'Via Ferrata', 'ST', 'This EDELRID classic has a very compact design and wear-resistant, elasticated webbing arms. It conforms to the new European safety standard for via ferrata sets. The new, far more compact shock absorber enables pleasant handling.', '["Rest loop situated directly at shock absorber", "Elasticated webbing keeps carabiners close to hand", "Optimized OneTouch II carabiners prevent fingers getting pinched between the carabiner gate and steel cable", "Energy absorber conforms to EN 958: 2017: low impact force for all weight classes", "Complies with EN standard 958: 2017, even in the event of 180° incorrect use", "Includes practical packing bag for storage and stowing in the backpack"]'::jsonb, '[{"label": "Material", "value": "Aluminium, Steel, HMPE, Polyamide"}, {"label": "Carabiner type", "value": "OneTouch II"}, {"label": "Weight Category", "value": "40 - 120 kg"}, {"label": "Weight", "value": "514g"}]'::jsonb, '["Bypass-save", "Made in Germany", "Fair Wear", "Technologies"]'::jsonb, '["oasis 138"]'::jsonb, '514g', '[]'::jsonb, 'EN 958, EN 12275', 'Made in Germany', '/images/products/74341.webp', 'VIA FERRATA', 'EN 958, EN 12275', '', true, 67),
('84506', 'X-Tube 25mm Loop NFC', 'Slings & Webbing', 'ST', '25 mm wide, sewn webbing sling with a sensational 30 kN breaking strength, available in various lengths.', '["NFC inside"]'::jsonb, '[{"label": "Material", "value": "Polyamide"}, {"label": "Width", "value": "25 mm"}, {"label": "Minimum breaking strength", "value": "30 kN"}]'::jsonb, '["Fair Wear", "Technologies"]'::jsonb, '["icemint 329", "night 017", "oasis 138", "red 200"]'::jsonb, null, '[{"length": "60 CM", "weight": "57g"}, {"length": "80 CM", "weight": "72g"}, {"length": "120 CM", "weight": "108g"}, {"length": "150 CM", "weight": "135g"}, {"length": "200 CM", "weight": "180g"}]'::jsonb, 'EN 354, EN 566, EN 795 Typ B', null, '/images/products/84506.webp', 'SLING', 'EN 354, EN 566, EN 795 Typ B', '', true, 68),
('84037', 'Cupid Swivel Mini', 'Hardware Accessories', 'ST', 'The ball-bearing-mounted swivel for connecting rope elements, slings, and metal components is ideal for rope bridges, directly tying in haul bags, and creating connections for uses where the shortest possible system length is required. The centering geometrics ensure that loads on the CUPID SWIVEL MINI are ideally positioned at all times.', '["Small, ball-bearing-mounted swivel rotates reliably even under high loads"]'::jsonb, '[{"label": "Certification", "value": "PPE-R/11.135"}, {"label": "Material", "value": "Aluminium"}, {"label": "Minimum breaking strength", "value": "23 kN"}]'::jsonb, '[]'::jsonb, '["icemint-night 377"]'::jsonb, null, '[]'::jsonb, 'PPE-R/11.135', null, '/images/products/84037.webp', 'HARDWARE', 'PPE-R/11.135', '', true, 69),
('71879', 'Hudson Hammer', 'Hardware Accessories', 'ST', 'The perfect big wall hammer.', '["Shock-absorbing hickory shaft", "Well-weighted head with point for levering pegs", "Hammer holster (sold separately)"]'::jsonb, '[{"label": "Material", "value": "Steel, Hickory"}, {"label": "Weight", "value": "670g"}]'::jsonb, '["Made in Germany"]'::jsonb, '["no color 000"]'::jsonb, '670g', '[]'::jsonb, null, 'Made in Germany', '/images/products/71879.webp', 'HARDWARE', '—', '', true, 70),
('88943', 'Master Rig II', 'Hardware Accessories', 'ST', 'Large, robust aluminium rigging plate for use in complex systems.', '["7 mm thick", "Hole diameter: 20 mm", "Central opening can take up to three carabiners", "Wrought construction for optimum material utilisation. Low weight and high strength", "Dimensions: 98 x 149 x 7 mm"]'::jsonb, '[{"label": "Certification", "value": "CNB/P 11.114 PfE"}, {"label": "Material", "value": "Aluminium"}, {"label": "Minimum breaking strength", "value": "40kN"}, {"label": "Weight", "value": "165g"}]'::jsonb, '[]'::jsonb, '["night 017"]'::jsonb, '165g', '[]'::jsonb, 'CNB/P 11.114 PfE', null, '/images/products/88943.webp', 'RIGGING', 'CNB/P 11.114 PfE', '', true, 71),
('88942', 'Mini Rig', 'Hardware Accessories', 'ST', 'Small, lightweight aluminium rigging plate suitable for extending from one to three anchor points.', '["Hole diameter: 20 mm", "Central opening can take up to three carabiners", "Wrought construction for optimum material utilisation. Low weight and high strength", "6 mm thick", "Maximum breaking strength: 36 kN"]'::jsonb, '[{"label": "Certification", "value": "CNB/P 11.114 PfE"}, {"label": "Material", "value": "Aluminium"}, {"label": "Minimum breaking strength", "value": "30kN"}, {"label": "Weight", "value": "62g"}]'::jsonb, '[]'::jsonb, '["orange 227"]'::jsonb, '62g', '[]'::jsonb, 'CNB/P 11.114 PfE', null, '/images/products/88942.webp', 'RIGGING', 'CNB/P 11.114 PfE', '', true, 72),
('84006', 'Ring Alu', 'Spare Parts', 'ST', 'Lightweight aluminum ring for rope bridges, for example on tree-care harnesses but also for installing anchor points.', '["Outer diameter: 64 mm", "Inner diameter: 40 mm"]'::jsonb, '[{"label": "Certification", "value": "CE"}, {"label": "Material", "value": "Aluminium"}, {"label": "Minimum breaking strength", "value": "30kN"}, {"label": "Weight", "value": "55g"}]'::jsonb, '[]'::jsonb, '["night 017", "oasis 138"]'::jsonb, '55g', '[]'::jsonb, 'CE', null, '/images/products/84006.webp', 'SPARE', 'CE', '', true, 73),
('35707', 'Mystix', 'Climbing Shoes — High-End', 'PA', 'Another member to our High-End range that was developed in close cooperation with our top athletes. The MYSTIX is a high-end climbing shoe with a powerful downturn for steep to extreme overhanging routes in the climbing gym and at the crag. Built on an aggressive and pointed last, the shoe allows very precise footwork on vertical and overhanging terrain. It offers great support on small edges while remaining flexible enough to impress in modern bouldering gyms which often possess many large volumes and slopers. In order to achieve these properties, the MYSTIX features a midsole which was specially developed using CAD Software. In addition, the strong downturn optimally supports the foot muscles in steep terrain. The crossed Velcro strap closure system permits individual adjustment with one quick pull. The MYSTIX is quick to take on and off without compromising on performance. In order to achieve even more feeling when stepping onto a hold, the toe area has been designed to be particularly soft. Additionally, the shoe features an extra sensitive Vibram XS Grip sole (4.0 mm). The toe area is made partially from leather, so that this part adjusts even more to the individual toe shape. The fit of the MYSTIX corresponds to your street shoe size. Performance-oriented climbers can also choose the MYSTIX max. one size smaller. For an optimal fit, we recommend measuring your feet with the help of our sizing chart.', '["Powerful downturn", "High-end bouldering and climbing shoe for steep to extreme overhanging routes in the climbing gym and at the crag", "Especially soft forefoot with extra sensitive Vibram XS Grip sole (4.0 mm) for even more feeling when stepping or hooking", "Individual adjustment to the foot and toe shape thanks to crossed fasteners and leather in the toe area", "Specially designed 2-zone midsole", "UK sizes 3 – 12"]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "ambitious"}, {"label": "Shoe shape", "value": "strongly asymmetric"}, {"label": "Upper", "value": "Microfiber"}, {"label": "Midsole", "value": "RC-FLEX"}, {"label": "Last shape", "value": "strongly asymmetric"}, {"label": "Closing System", "value": "Single Lace"}, {"label": "Midsole Material", "value": "RX-FLEX"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "Vibram XS Grip 3,5mm"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 Allround 2,0mm, moulded"}, {"label": "Weight (Size UK 7,5)", "value": "252g"}, {"label": "Tongue", "value": "Elastic Mesh"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["snow 047"]'::jsonb, null, '[{"length": "3", "weight": "340g"}, {"length": "3,5", "weight": "400g"}, {"length": "4", "weight": "420g"}, {"length": "4,5", "weight": "430g"}, {"length": "5", "weight": "450g"}, {"length": "5,5", "weight": "460g"}, {"length": "6", "weight": "476g"}, {"length": "6,5", "weight": "490g"}, {"length": "7", "weight": "500g"}, {"length": "7,5", "weight": "520g"}, {"length": "8", "weight": "537g"}, {"length": "8,5", "weight": "555g"}, {"length": "9", "weight": "570g"}, {"length": "9,5", "weight": "590g"}, {"length": "10", "weight": "600g"}, {"length": "10,5", "weight": "620g"}, {"length": "11", "weight": "640g"}, {"length": "11,5", "weight": "660g"}, {"length": "12", "weight": "678g"}]'::jsonb, null, null, '/images/products/35707.webp', 'HIGH-END', '—', '', true, 74),
('35720', 'Sensor', 'Climbing Shoes — High-End', 'PA', 'When it comes to the SENSOR, the name says it all: it is the most sensitive shoe in our range and has been specially developed for climbing and bouldering on artificial holds as well as for competitions. The combination of a minimalistic midsole, high asymmetry, and a powerful downturn makes the SENSOR a highly sensitive and performance-oriented climbing shoe. An innovative system with a double slingshot prevents the pre-tensioning from waning over time. The Vibram XS Grip sole and a large toe patch provide outstanding grip exactly where it is needed. And that is not the only thing that is special about the sole: we have also varied the thickness from 1 to 4 mm to aid sensitivity—with lots of rubber where you need it and less where a good sense of feel is key. Thanks to the somewhat narrower, performance-oriented cut, the SENSOR fits the foot snuggly. The SENSOR runs small. Therefore, choose one size larger than your street shoe size. For the best fit, we recommend measuring your feet with the help of our sizing chart.', '["Powerful downturn", "UK sizes 3 – 12", "High-end bouldering and climbing shoe for steep to extreme overhanging routes in the climbing gym and at the crag", "Particularly sensitive forefoot with a shaped Vibram XS Grip sole for even more feeling when stepping or hooking", "Double slingshot preserves pre-tensioning"]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "aggressive"}, {"label": "Shoe shape", "value": "strongly asymmetric"}, {"label": "Upper", "value": "Microfiber 2,0mm"}, {"label": "Midsole", "value": "RC-SENSE"}, {"label": "Lining", "value": "Leather Heel"}, {"label": "Last shape", "value": "strongly asymmetric"}, {"label": "Closing System", "value": "Single VCR"}, {"label": "Midsole Material", "value": "RC-SENSE"}, {"label": "Rubber back/heel", "value": "Vibram XS Grip"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 ALLROUND 2,0mm-1,0mm / 50° shore, moulded"}, {"label": "Weight (Size UK 7,5)", "value": "256g"}, {"label": "Footbed", "value": "Microfiber / Suede leather (Toe Box / Heel)"}, {"label": "Tongue", "value": "Elastic Mesh"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["petrol 404"]'::jsonb, null, '[{"length": "3", "weight": "384g"}, {"length": "3,5", "weight": "393g"}, {"length": "4", "weight": "403g"}, {"length": "4,5", "weight": "412g"}, {"length": "5", "weight": "422g"}, {"length": "5,5", "weight": "431g"}, {"length": "6", "weight": "441g"}, {"length": "6,5", "weight": "450g"}, {"length": "7", "weight": "460g"}, {"length": "7,5", "weight": "470g"}, {"length": "8", "weight": "487g"}, {"length": "8,5", "weight": "505g"}, {"length": "9", "weight": "520g"}, {"length": "9,5", "weight": "540g"}, {"length": "10", "weight": "558g"}, {"length": "10,5", "weight": "570g"}, {"length": "11", "weight": "590g"}, {"length": "11,5", "weight": "610g"}, {"length": "12", "weight": "630g"}]'::jsonb, null, null, '/images/products/35720.webp', 'HIGH-END', '—', '', true, 75),
('35727', 'Voltage LV II', 'Climbing Shoes — High-End', 'PA', 'The trusted fit and all the features of the VOLTAGE, but for less voluminous, slimmer feet, especially in the forefoot—that''s what the VOLTAGE LV offers! Its powerful downturn combined with the claw shape in the toe area ensures the perfect move on an overhang. The perfectly tuned midsole supports the toes when standing on the smallest footholds, but at the same time is soft enough to significantly increase friction even in modern volume bouldering. Offset VCR straps allow the shoe to be quickly adjusted to your foot. The sock-like shaft design prevents rubbing and pressure points and makes the VOLTAGE LV comfortable despite its aggressive shape. The tongue on the VOLTAGE LV is made of breathable and elastic knitted fabric and starts below the outer ankle to prevent friction points here as well. The fit of the VOLTAGE LV corresponds to your street shoe size. Performance-oriented climbers can also choose the VOLTAGE LV max. one size smaller. For an optimal fit, we recommend measuring your feet with the help of our sizing chart.', '["Powerful downturn", "Low volume — especially shaped for slimmer feet", "UK sizes 3 - 8", "High-end bouldering and climbing shoe for steep to extreme overhanging routes in the climbing gym and at the crag", "Two offset VCR straps for optimal adjustment", "Specially shaped, sock-like upper construction", "High-quality leather footbed, upper made of dimensionally stable microfiber fabric", "Vibram XS Grip sole (4 mm) for even more feeling when stepping", "Perfectly matched midsole at forefoot (RC-TENSION)", "Breathable fine knit tongue"]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "aggressive"}, {"label": "Shoe shape", "value": "strongly asymmetric"}, {"label": "Upper", "value": "Microfiber 2,0mm"}, {"label": "Midsole", "value": "RC-TENSION"}, {"label": "Last shape", "value": "strongly asymmetric"}, {"label": "Closing System", "value": "Double VCR"}, {"label": "Midsole Material", "value": "RC-TENSION"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Weight (Size UK 7,5)", "value": "237g"}, {"label": "Footbed", "value": "Microfiber 2,0mm / Suede leather (Toe Box)"}, {"label": "Tongue", "value": "Polyester Knit"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear", "Low Volume"]'::jsonb, '["neon pink 104"]'::jsonb, null, '[{"length": "3", "weight": "362g"}, {"length": "3,5", "weight": "370g"}, {"length": "4", "weight": "390g"}, {"length": "4,5", "weight": "400g"}, {"length": "5", "weight": "420g"}, {"length": "5,5", "weight": "436g"}, {"length": "6", "weight": "450g"}, {"length": "6,5", "weight": "465g"}, {"length": "7", "weight": "480g"}, {"length": "7,5", "weight": "490g"}, {"length": "8", "weight": "510g"}]'::jsonb, null, null, '/images/products/35727.webp', 'HIGH-END', '—', '', true, 76),
('35708', 'Voltage Lace', 'Climbing Shoes — High-End', 'PA', 'With the fit of the VOLTAGE, the model VOLTAGE LACE is slightly stiffer and thus offers more support at the forefoot. This makes it particularly suitable for difficult routes on steep and overhanging crags. The wide, anatomically designed last with a powerful downturn remains. This optimally supports the foot when standing on small footholds. Additionally, the leather parts in the footbed adjust themselves to the toe shape. A thin lining in the toe box increases comfort and prevents the stretching of the upper material. The asymmetrical lacing makes individual adjustment possible and allows a better pressure distribution on the instep. In addition, this arrangement provides more space for the large toe patch, which remains flexible thanks to well thought-out cuts. The lacing system can be tightened evenly with a single pull and is reinforced at neuralgic points. The overlapping tongue, which covers the instep, avoids unpleasant pressure points. The fit of the VOLTAGE LACE corresponds to your street shoe size. Performance-oriented climbers can also choose the VOLTAGE LACE max. one size smaller. For an optimal fit, we recommend measuring your feet with the help of our sizing chart.', '["Powerful downturn", "High-end bouldering and climbing shoe for steep to extreme overhanging terrain", "Asymmetric lacing for quick and individual adjustment", "Special overlapping tongue construction for more comfort", "Upper made of high-quality leather and microfiber mix", "UK sizes 3 – 12"]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "aggressive"}, {"label": "Shoe shape", "value": "strongly asymmetric"}, {"label": "Upper", "value": "Suede leather | Microfiber 2,0mm"}, {"label": "Midsole", "value": "RC-TENSION"}, {"label": "Lining", "value": "Microfiber 0,5mm"}, {"label": "Last shape", "value": "strongly asymmetric"}, {"label": "Closing System", "value": "Lace"}, {"label": "Midsole Material", "value": "RC-TENSION"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "RX-1 Allround 3,0mm"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 Allround 2,0mm, moulded"}, {"label": "Weight (Size UK 7,5)", "value": "267g"}, {"label": "Footbed", "value": "Microfiber 2,0mm / Suede leather (Toe Box)"}, {"label": "Tongue", "value": "Suede leather 2,0mm"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["wasabi 036"]'::jsonb, null, '[{"length": "3", "weight": "390g"}, {"length": "3,5", "weight": "410g"}, {"length": "4", "weight": "420g"}, {"length": "4,5", "weight": "440g"}, {"length": "5", "weight": "450g"}, {"length": "5,5", "weight": "460g"}, {"length": "6", "weight": "480g"}, {"length": "6,5", "weight": "490g"}, {"length": "7", "weight": "500g"}, {"length": "7,5", "weight": "520g"}, {"length": "8", "weight": "536g"}, {"length": "8,5", "weight": "550g"}, {"length": "9", "weight": "565g"}, {"length": "9,5", "weight": "580g"}, {"length": "10", "weight": "600g"}, {"length": "10,5", "weight": "610g"}, {"length": "11", "weight": "630g"}, {"length": "11,5", "weight": "640g"}, {"length": "12", "weight": "660g"}]'::jsonb, null, null, '/images/products/35708.webp', 'HIGH-END', '—', '', true, 77),
('35735', 'Voltage X', 'Climbing Shoes — High-End', 'PA', 'The VOLTAGE X is a sensitive, high-end shoe that has been fully tailored to the needs of modern, dynamic bouldering and climbing, whether large volumes, steep climbs, roofs, hooks, or jumps. The newly developed RC-TENSION S midsole enables the combination of an aggressive tension system with a soft, sensitive shoe design. The Vibram XS Grip split sole furthermore provides good grip. The large toe patch and anatomically shaped heel enable optimum power transfer when hooking. The relatively wide rand provides a secure yet comfortable fit compatible with many feet shapes. The fast-lacing system with a VCR strap enables individual adjustment with one quick hand movement. The VOLTAGE X is a comfortable, high-end shoe for both crags and gyms.', '[]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "aggressive"}, {"label": "Shoe shape", "value": "strongly asymmetric"}, {"label": "Midsole", "value": "RC-TENSION S"}, {"label": "Last shape", "value": "strongly asymmetric"}, {"label": "Closing System", "value": "Speed lace"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Footbed", "value": "Microfiber 2,0mm"}, {"label": "Tongue", "value": "Elastic Webbing"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["red-marine 269"]'::jsonb, null, '[{"length": "3", "weight": "370g"}, {"length": "3,5", "weight": "390g"}, {"length": "4", "weight": "410g"}, {"length": "4,5", "weight": "430g"}, {"length": "5", "weight": "450g"}, {"length": "5,5", "weight": "470g"}, {"length": "6", "weight": "490g"}, {"length": "6,5", "weight": "510g"}, {"length": "7", "weight": "530g"}, {"length": "7,5", "weight": "550g"}, {"length": "8", "weight": "570g"}, {"length": "8,5", "weight": "590g"}, {"length": "9", "weight": "610g"}, {"length": "9,5", "weight": "630g"}, {"length": "10", "weight": "650g"}, {"length": "10,5", "weight": "670g"}, {"length": "11", "weight": "690g"}, {"length": "11,5", "weight": "710g"}, {"length": "12", "weight": "730g"}]'::jsonb, null, null, '/images/products/35735.webp', 'HIGH-END', '—', '', true, 78),
('35730', 'Clue', 'Climbing Shoes — Performance', 'PA', 'Got no clue? We got it! With its particularly sensitive and strongly performance-oriented construction and lots of rubber, the CLUE is the ideal choice for bouldering problems, slabs and demanding overhang climbing. The aggressive shape brings a great deal of tension despite the particularly soft Vibram XS sole for optimal sensitivity. The stretch tongue allows for a comfortable step-in and still keeps the shoe reliably on the foot. With its timeless design, the CLUE is the perfect shoe to be fired up for sending today.', '["UK sizes 3 – 12", "Sensitive performance slipper with 1 VCR and big toe patch for bouldering and climbing indoors and on rock", "RC-SENSE midsole for edge stability with maximum sensitivity and best clawing properties", "Vibram XS grip sole for a lot of feeling when starting and high friction values", "Slightly asymmetrical", "Aggressive downturn and pretension"]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "aggressive"}, {"label": "Shoe shape", "value": "slightly asymmetric"}, {"label": "Upper", "value": "Microfibre 2,0mm"}, {"label": "Midsole", "value": "RC-SENSE"}, {"label": "Lining", "value": "Microfibre 0,8mm"}, {"label": "Last shape", "value": "slightly asymmetric"}, {"label": "Closing System", "value": "Slipper Single VCR"}, {"label": "Midsole Material", "value": "RC-SENSE"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "RX-1 Allround 3,0mm"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Footbed", "value": "Microfiber 2,0mm"}, {"label": "Tongue", "value": "Elastic Webbing"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear", "Vegan friendly"]'::jsonb, '["night-snow 921"]'::jsonb, null, '[{"length": "3", "weight": "310g"}, {"length": "3,5", "weight": "330g"}, {"length": "4", "weight": "340g"}, {"length": "4,5", "weight": "350g"}, {"length": "5", "weight": "370g"}, {"length": "5,5", "weight": "380g"}, {"length": "6", "weight": "390g"}, {"length": "6,5", "weight": "400g"}, {"length": "7", "weight": "418g"}, {"length": "7,5", "weight": "430g"}, {"length": "8", "weight": "456g"}, {"length": "8,5", "weight": "468g"}, {"length": "9", "weight": "480g"}, {"length": "9,5", "weight": "490g"}, {"length": "10", "weight": "500g"}, {"length": "10,5", "weight": "520g"}, {"length": "11", "weight": "530g"}, {"length": "11,5", "weight": "540g"}, {"length": "12", "weight": "556g"}]'::jsonb, null, null, '/images/products/35730.webp', 'PERFORMANCE', '—', '', true, 79),
('35722', 'Fusion II', 'Climbing Shoes — Performance', 'PA', 'The new FUSION has been completely overhauled. The rand has more downturn and a slightly wider forefoot. A further new feature is the innovative fastening system, which combines the benefits of VCR and laces to enable rapid and customized adjustment to the feet. The laces are made of extremely strong and abrasion-resistant Technora aramid fibers left over in our production department and normally used for paragliders. The tongue made of 3 mm thick neoprene improves the comfort and distributes the closure forces more evenly. Thanks to these features, the FUSION offers enhanced performance and a more individual fit while still remaining a versatile all-rounder. This is further highlighted by the full-surface RX-1 ALLROUND sole, which impresses with particularly well-balanced properties with regard to friction, sensitivity, durability, and edge stability. The fit of the FUSION corresponds to your street shoe size. Performance-oriented climbers can also choose the FUSION max. half a size smaller. For an optimal fit, we recommend measuring your feet with the help of our sizing chart.', '["UK sizes 3 – 12", "Low volume — especially shaped for slimmer feet", "A sporty all-rounder for long sessions in the climbing gym, multi-pitch routes and alpine tours", "Toe box made of microfiber material minimizes the fabric stretch and ensures high dimensional stability", "Innovative, combined VCR and lace closure enables a rapid and customized fit"]'::jsonb, '[{"label": "Downturn", "value": "ambitious"}, {"label": "Shoe shape", "value": "slightly asymmetric"}, {"label": "Upper", "value": "Forefoot: Microfiber 2,0mm | Hindfoot: Suede leather 2,0mm"}, {"label": "Midsole", "value": "RC-SUPPORT"}, {"label": "Lining", "value": "Microfiber 0,5mm / 0,8mm"}, {"label": "Last shape", "value": "slightly asymmetric"}, {"label": "Closing System", "value": "Speed lace"}, {"label": "Midsole Material", "value": "RC-SUPPORT"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Weight (Size UK 7,5)", "value": "269g"}, {"label": "Footbed", "value": "Microfiber 2,0mm / Suede leather (Toe Box)"}, {"label": "Tongue", "value": "Neoprene 3,0mm"}, {"label": "Rubber", "value": "RX-1 ALLROUND"}]'::jsonb, '["Fair Wear"]'::jsonb, '["oasis 138"]'::jsonb, null, '[{"length": "3", "weight": "410g"}, {"length": "3,5", "weight": "420g"}, {"length": "4", "weight": "430g"}, {"length": "4,5", "weight": "440g"}, {"length": "5", "weight": "450g"}, {"length": "5,5", "weight": "460g"}, {"length": "6", "weight": "470g"}, {"length": "6,5", "weight": "480g"}, {"length": "7", "weight": "490g"}, {"length": "7,5", "weight": "500g"}, {"length": "8", "weight": "524g"}, {"length": "8,5", "weight": "540g"}, {"length": "9", "weight": "563g"}, {"length": "9,5", "weight": "580g"}, {"length": "10", "weight": "600g"}, {"length": "10,5", "weight": "620g"}, {"length": "11", "weight": "640g"}, {"length": "11,5", "weight": "660g"}, {"length": "12", "weight": "680g"}]'::jsonb, null, null, '/images/products/35722.webp', 'PERFORMANCE', '—', '', true, 80),
('35723', 'Fusion LV II', 'Climbing Shoes — Performance', 'PA', 'The FUSION LV has been completely overhauled. The low volume version of the FUSION has a slimmer overall cut, making it particularly ideal for a more feminine foot or narrower fit. The rand has more downturn and a slightly wider forefoot. A further new feature is the innovative fastening system, which combines the benefits of VCR and laces to enable rapid and customized adjustment to the feet. The laces are made of extremely strong and abrasion-resistant Technora aramid fibers left over in our production department and normally used for paragliders. The tongue made of 3 mm thick neoprene improves the comfort and distributes the closure forces more evenly. Thanks to these features, the FUSION LV offers enhanced performance and a more individual fit while still remaining a versatile all-rounder. This is further highlighted by the full-surface RX-1 ALLROUND sole, which impresses with particularly well-balanced properties with regard to friction, sensitivity, durability, and edge stability. The fit of the FUSION LV corresponds to your street shoe size. Performance-oriented climbers can also choose the FUSION LV max. half a size smaller. For an optimal fit, we recommend measuring your feet with the help of our sizing chart.', '["Low volume — especially shaped for slimmer feet", "UK sizes 3 - 8", "A sporty all-rounder for long sessions in the climbing gym, multi-pitch routes and alpine tours", "Toe box made of microfiber material minimizes the fabric stretch and ensures high dimensional stability", "Innovative, combined VCR and lace closure enables a rapid and customized fit"]'::jsonb, '[{"label": "Downturn", "value": "ambitious"}, {"label": "Shoe shape", "value": "slightly asymmetric"}, {"label": "Upper", "value": "Forefoot: Microfiber 2,0mm | Hindfoot: Suede leather 2,0mm"}, {"label": "Midsole", "value": "RC-SUPPORT"}, {"label": "Lining", "value": "Microfiber 0,5mm / 0,8mm"}, {"label": "Last shape", "value": "slightly asymmetric"}, {"label": "Closing System", "value": "Speed lace"}, {"label": "Midsole Material", "value": "RC-SUPPORT"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Weight (Size UK 7,5)", "value": "233g"}, {"label": "Footbed", "value": "Microfiber 2,0mm / Suede leather (Toe Box)"}, {"label": "Tongue", "value": "Neoprene 3,0mm"}, {"label": "Rubber", "value": "RX-1 ALLROUND 4,5mm"}]'::jsonb, '["Fair Wear", "Low Volume"]'::jsonb, '["raspberry 222"]'::jsonb, null, '[{"length": "3", "weight": "422g"}, {"length": "3,5", "weight": "436g"}, {"length": "4", "weight": "450g"}, {"length": "4,5", "weight": "464g"}, {"length": "5", "weight": "478g"}, {"length": "5,5", "weight": "492g"}, {"length": "6", "weight": "506g"}, {"length": "6,5", "weight": "520g"}, {"length": "7", "weight": "534g"}, {"length": "7,5", "weight": "548g"}, {"length": "8", "weight": "562g"}]'::jsonb, null, null, '/images/products/35723.webp', 'PERFORMANCE', '—', '', true, 81),
('35728', 'Magnet II', 'Climbing Shoes — Performance', 'PA', 'The MAGNET is THE specialist for small slats and increases your attractive force when sport climbing or on multi-pitch routes. It is a performance-oriented climbing shoe that also offers outstanding comfort. The RC-TENSION midsole offers stability across the entire shoe. Once again, we specifically adapted the midsole design to the MAGNET to create the perfect balance of sensitivity and support when standing on small footholds. The last with moderate pre-tensioning combined with the sock-like upper design ensures that the MAGNET still remains comfortable even when worn for longer periods. The tongue is made from breathable knitted fabric comprising recycled yarn. The fit of the MAGNET corresponds to your street shoe size. Performance-oriented climbers can also choose the MAGNET max. half a size smaller. For an optimal fit, we recommend measuring your feet with the help of our sizing chart.', '[]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "ambitious"}, {"label": "Shoe shape", "value": "slightly asymmetric"}, {"label": "Upper", "value": "Microfiber 2,0mm"}, {"label": "Midsole", "value": "RC-TENSION"}, {"label": "Last shape", "value": "slightly asymmetric"}, {"label": "Closing System", "value": "Double VCR"}, {"label": "Midsole Material", "value": "RC-SUPPORT"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "RX-2 TECHGRIP 4,0mm"}, {"label": "Rubber rand", "value": "RX-2 TECHGRIP 2,0mm"}, {"label": "Weight (Size UK 7,5)", "value": "269g"}, {"label": "Footbed", "value": "Microfiber 2,0mm | Suede leather (Toe Box)"}, {"label": "Tongue", "value": "Recycled Polyester Knit"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["dark blue 054"]'::jsonb, null, '[{"length": "3", "weight": "410g"}, {"length": "3,5", "weight": "420g"}, {"length": "4", "weight": "433g"}, {"length": "4,5", "weight": "445g"}, {"length": "5", "weight": "456g"}, {"length": "5,5", "weight": "468g"}, {"length": "6", "weight": "479g"}, {"length": "6,5", "weight": "490g"}, {"length": "7", "weight": "500g"}, {"length": "7,5", "weight": "510g"}, {"length": "8", "weight": "526g"}, {"length": "8,5", "weight": "537g"}, {"length": "9", "weight": "537g"}, {"length": "9,5", "weight": "548g"}, {"length": "10", "weight": "549g"}, {"length": "10,5", "weight": "560g"}, {"length": "11", "weight": "610g"}, {"length": "11,5", "weight": "626g"}, {"length": "12", "weight": "637g"}]'::jsonb, null, null, '/images/products/35728.webp', 'PERFORMANCE', '—', '', true, 82),
('35738', 'Magnet Lace', 'Climbing Shoes — Performance', 'PA', 'The MAGNET LACE is a performance-oriented yet outstandingly comfortable climbing shoe. Like the MAGNET, the MAGNET LACE is a specialist for small ledges. The lace system enables a particularly good fit while midsole design offers the perfect balance between sensitivity and support to provide the necessary pressure on small footholds and enable precise footwork. The special last shape with moderate pre-tensioning ensures that the MAGNET LACE still remains comfortable even when worn for extended periods. The breathable microfiber upper and lined knitted tongue further enhance the comfortable feel while the tried-and-tested Vibram XS Grip sole provides plenty of friction for all areas of use. The MAGNET LACE is a versatile climbing shoe for ambitious and performance-oriented climbers who undertake a range of disciplines such as sport, multi-pitch, and trad climbing, and want a mixture of precision, edge stability, and comfort.', '[]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "ambitious"}, {"label": "Shoe shape", "value": "slightly asymmetric"}, {"label": "Upper", "value": "Microfiber 2,0mm"}, {"label": "Midsole", "value": "RC-SUPPORT"}, {"label": "Last shape", "value": "slightly asymmetric"}, {"label": "Closing System", "value": "Lace"}, {"label": "Midsole Material", "value": "RC-SUPPORT"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "RX-2 TECHGRIP 4,0mm"}, {"label": "Rubber rand", "value": "RX-2 TECHGRIP 2,0mm"}, {"label": "Footbed", "value": "Microfiber / Suede leather (Toe Box / Heel)"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["stoneblue-grass 307"]'::jsonb, null, '[{"length": "3", "weight": "445g"}, {"length": "3,5", "weight": "452g"}, {"length": "4", "weight": "459g"}, {"length": "4,5", "weight": "466g"}, {"length": "5", "weight": "473g"}, {"length": "5,5", "weight": "480g"}, {"length": "6", "weight": "487g"}, {"length": "6,5", "weight": "494g"}, {"length": "7", "weight": "501g"}, {"length": "7,5", "weight": "508g"}, {"length": "8", "weight": "515g"}, {"length": "8,5", "weight": "522g"}, {"length": "9", "weight": "529g"}, {"length": "9,5", "weight": "536g"}, {"length": "10", "weight": "543g"}, {"length": "10,5", "weight": "550g"}, {"length": "11", "weight": "557g"}, {"length": "11,5", "weight": "564g"}, {"length": "12", "weight": "571g"}]'::jsonb, null, null, '/images/products/35738.webp', 'PERFORMANCE', '—', '', true, 83),
('35739', 'Voltage III', 'Climbing Shoes — Performance', 'PA', 'The VOLTAGE is a high-end shoe that offers outstanding precision, maximum power transfer, and excellent sensitivity. Its wide, anatomically designed last shape offers plenty of toe room while aggressive pre-tensioning and asymmetry transmit impressive force to the toes. The tried-and-tested, anatomically shaped heel design of the VOLTAGE range enables rock-solid heel hooks. Just in case, the shoe also features a large toe patch. The fit can be adjusted using the two VCR straps, with the large, main strap holding the heel securely in place while the offset smaller strap enables a snug midfoot fit. The two-part elasticated material offers different levels of tension to make the shoe easier to put on and take off. The VOLTAGE is the perfect choice for advanced and professional climbers looking for a precise shoe for sport climbing and bouldering for demanding overhangs and highly technical routes.', '[]'::jsonb, '[{"label": "Sole", "value": "Vibram XS Grip"}, {"label": "Downturn", "value": "aggressive"}, {"label": "Shoe shape", "value": "strongly asymmetric"}, {"label": "Upper", "value": "Microfiber 2,0mm"}, {"label": "Midsole", "value": "RC-TENSION"}, {"label": "Last shape", "value": "strongly asymmetric"}, {"label": "Closing System", "value": "Double Velcro"}, {"label": "Midsole Material", "value": "RC-TENSION"}, {"label": "Rubber front", "value": "Vibram XS Grip 4,0mm"}, {"label": "Rubber back/heel", "value": "RX-1 Allround 3,0mm"}, {"label": "Rubber rand", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Toe patch", "value": "RX-1 ALLROUND 2,0mm"}, {"label": "Footbed", "value": "Suede leather"}, {"label": "Rubber", "value": "Vibram XS Grip"}]'::jsonb, '["Fair Wear"]'::jsonb, '["topaz 094"]'::jsonb, null, '[{"length": "3", "weight": "501g"}, {"length": "3,5", "weight": "508g"}, {"length": "4", "weight": "515g"}, {"length": "4,5", "weight": "522g"}, {"length": "5", "weight": "529g"}, {"length": "5,5", "weight": "536g"}, {"length": "6", "weight": "543g"}, {"length": "6,5", "weight": "550g"}, {"length": "7", "weight": "557g"}, {"length": "7,5", "weight": "564g"}, {"length": "8", "weight": "571g"}, {"length": "8,5", "weight": "578g"}, {"length": "9", "weight": "585g"}, {"length": "9,5", "weight": "592g"}, {"length": "10", "weight": "599g"}, {"length": "10,5", "weight": "606g"}, {"length": "11", "weight": "613g"}, {"length": "11,5", "weight": "620g"}, {"length": "12", "weight": "627g"}]'::jsonb, null, null, '/images/products/35739.webp', 'PERFORMANCE', '—', '', true, 84),
('72177', 'Boulder Bag Herkules', 'Chalk Bags', 'ST', 'Large, spacious chalk bag for high demands in bouldering. Thanks to its large contact surface, it stands on its own.', '["Various brush holders", "Made of bluesign®-certified materials", "100% dustproof roll closure", "Zipped pocket with key clip for a cell phone and accessories", "Large mesh bag", "Carrying handle"]'::jsonb, '[{"label": "Material", "value": "Polyester"}, {"label": "Diameter", "value": "190 mm"}, {"label": "Depth", "value": "21 cm"}, {"label": "Weight", "value": "166 g"}]'::jsonb, '["bluesign®", "Climb Green", "Fair Wear"]'::jsonb, '["dolphin 038", "flame 024"]'::jsonb, '166 g', '[]'::jsonb, null, null, '/images/products/72177.webp', 'CHALK', '—', '', true, 85),
('72198', 'Chalk Bag Ambassador II', 'Chalk Bags', 'ST', 'A particularly light chalk bag with a sporty design that not only reflects our high-end ACE harness from a visual perspective—including the brush holders—but is also made from the same material. The AMBASSADOR has a particularly small pack size and can be quickly and securely sealed with a single movement using the drawcord.', '["Drawcord closure for easy tightening", "Two brush holders", "Light chalk bag with a small pack size", "Sporty ACE design"]'::jsonb, '[{"label": "Material", "value": "Polyamide, Polyester"}, {"label": "Weight", "value": "71 g"}]'::jsonb, '["Fair Wear"]'::jsonb, '["neon green 499", "night 017"]'::jsonb, '71 g', '[]'::jsonb, null, null, '/images/products/72198.webp', 'CHALK', '—', '', true, 86),
('72179', 'Chalk Bag Monoblock', 'Chalk Bags', 'ST', 'Casual chalk bag that offers plenty of space for not just chalk but also three brushes and your keys. The drawcord enables it to be quickly and securely sealed in a single movement.', '["Made of bluesign®-certified materials", "3 brush holders", "Drawcord closure for easy tightening", "VCR key pocket"]'::jsonb, '[{"label": "Material", "value": "Polyester"}, {"label": "Diameter", "value": "14 mm"}, {"label": "Depth", "value": "16 cm"}, {"label": "Weight", "value": "93 g"}]'::jsonb, '["bluesign®", "Climb Green", "Fair Wear"]'::jsonb, '["red-stone 943", "royal-pebbles 052", "stoneblue-grass 307", "vinered-amber 873"]'::jsonb, '93 g', '[]'::jsonb, null, null, '/images/products/72179.webp', 'CHALK', '—', '', true, 87),
('72182', 'Chalk Bag Muffin', 'Chalk Bags', 'ST', 'Little chalk bag with a cool image. Optimized for children''s hands.', '["Made of bluesign®-certified materials", "Drawcord closure for easy tightening", "Two brush holders"]'::jsonb, '[{"label": "Material", "value": "Polyester"}, {"label": "Diameter", "value": "10 mm"}, {"label": "Depth", "value": "12 cm"}, {"label": "Weight", "value": "63 g"}]'::jsonb, '["bluesign®", "Kids", "Climb Green", "Fair Wear"]'::jsonb, '["chute green 459", "polar 065"]'::jsonb, '63 g', '[]'::jsonb, null, null, '/images/products/72182.webp', 'CHALK', '—', '', true, 88),
('72185', 'Chalk Bag Rodeo TC', 'Chalk Bags', 'ST', 'Stylish, fleece-lined chalk bag with a drawcord. The namesake Tommy Caldwell (TC) is not only a professional climber but also a passionate environmentalist. Together, we are supporting the organization POW (Protect Our Winters) by donating 1% of the worldwide revenue from the sale of this chalk bag.', '["Made of bluesign®-certified materials", "Drawcord closure for easy tightening", "Two brush holders"]'::jsonb, '[{"label": "Material", "value": "Polyester"}, {"label": "Diameter", "value": "13.5 mm"}, {"label": "Depth", "value": "17 cm"}, {"label": "Weight", "value": "84 g"}]'::jsonb, '["bluesign®", "Climb Green", "Fair Wear"]'::jsonb, '["beetroot 158", "black 010"]'::jsonb, '84 g', '[]'::jsonb, null, null, '/images/products/72185.webp', 'CHALK', '—', '', true, 89),
